--- conky.orig/Makefile	2010-07-12 06:15:51.000000000 +0300
+++ conky/Makefile	2010-10-13 09:16:00.000000000 +0300
@@ -6,7 +6,7 @@
 #

 PORTNAME=	conky
-PORTVERSION=	1.8.0
+PORTVERSION=	1.8.1
 CATEGORIES=	sysutils
 MASTER_SITES=	SF

@@ -24,8 +24,7 @@
